function parseHour(str) {
  const m = (str || '').match(/(\d+)시/);
  return m ? parseInt(m[1], 10) : 0;
}
const DAY_MAP = { '일': 0, '월': 1, '화': 2, '수': 3, '목': 4, '금': 5, '토': 6 };
const now = new Date();
const targetYear = now.getMonth() === 11 ? now.getFullYear() + 1 : now.getFullYear();
const targetMonth = now.getMonth() === 11 ? 1 : now.getMonth() + 2;

function toKSTDatetime(date, hour) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  const hh = String(hour).padStart(2, '0');
  return yyyy + '-' + mm + '-' + dd + 'T' + hh + ':00:00+09:00';
}

function getDatesInMonth(year, month, dow) {
  const dates = [];
  const d = new Date(year, month - 1, 1);
  while (d.getMonth() === month - 1) {
    if (d.getDay() === dow) dates.push(new Date(d));
    d.setDate(d.getDate() + 1);
  }
  return dates;
}

function getWeekOfMonth(date) {
  const firstDay = new Date(date.getFullYear(), date.getMonth(), 1);
  const firstDow = firstDay.getDay() === 0 ? 7 : firstDay.getDay();
  return Math.ceil((date.getDate() + firstDow - 1) / 7);
}

// multi_select 필드 읽기
function getMultiSelect(props, key) {
  const field = props[key];
  if (!field) return [];
  const ms = field['multi_select'];
  if (!ms || !Array.isArray(ms)) return [];
  return ms.map(function(s) { return s.name; });
}

// select 필드 읽기 (정규보충은 select 타입)
function getSelect(props, key) {
  const field = props[key];
  if (!field) return null;
  const sel = field['select'];
  if (!sel) return null;
  return sel.name || null;
}

const aggregated = $input.first();
const classList = aggregated.json.data || [];
const records = [];

for (const cls of classList) {
  const props = cls.properties || {};
  const classId = cls.id;

  const titleField = props['반명'];
  const titleArr = titleField ? (titleField['title'] || []) : [];
  const 반명 = titleArr.map(function(t) { return t.plain_text; }).join('');
  if (!반명) continue;

  const studentsField = props['Students'];
  const studentsRel = studentsField ? (studentsField['relation'] || []) : [];
  const studentIds = studentsRel.map(function(r) { return r.id; });

  // 정규수업 슬롯
  // 수업1 + 시간 1, 수업2 + 시간2, 수업3 + 시간3 (실제 필드명 확인)
  const timeFieldNames = ['시간 1', '시간2', '시간3'];
  const slots = [];
  for (let i = 1; i <= 3; i++) {
    const days = getMultiSelect(props, '수업 ' + i);
    const times = getMultiSelect(props, timeFieldNames[i - 1]);
    for (const day of days) {
      slots.push({ day: day, hour: times.length > 0 ? parseHour(times[0]) : 0 });
    }
  }

  // 정규보충 슬롯
  // 정규보충: select 타입, 시간: '시간 4' 필드
  const 보충Day = getSelect(props, '정규보충');
  const 보충Times = getMultiSelect(props, '시간 4');
  if (보충Day && 보충Day in DAY_MAP) {
    slots.push({ day: 보충Day, hour: 보충Times.length > 0 ? parseHour(보충Times[0]) : 0 });
  }

  if (slots.length === 0) continue;

  // 해당 월 전체 날짜 수집
  const allDates = [];
  for (const slot of slots) {
    if (!(slot.day in DAY_MAP)) continue;
    const dates = getDatesInMonth(targetYear, targetMonth, DAY_MAP[slot.day]);
    for (const d of dates) {
      allDates.push({ date: d, hour: slot.hour });
    }
  }
  allDates.sort(function(a, b) { return a.date - b.date || a.hour - b.hour; });

  // 주차별 그룹핑 후 넘버링
  const weekGroups = {};
  for (const entry of allDates) {
    const w = getWeekOfMonth(entry.date);
    if (!weekGroups[w]) weekGroups[w] = [];
    weekGroups[w].push(entry);
  }

  const weekKeys = Object.keys(weekGroups).sort(function(a, b) { return Number(a) - Number(b); });
  for (const w of weekKeys) {
    const group = weekGroups[w];
    group.sort(function(a, b) { return a.date - b.date || a.hour - b.hour; });
    for (let idx = 0; idx < group.length; idx++) {
      const entry = group[idx];
      records.push({
        json: {
          title: 반명 + ' ' + targetMonth + '월 ' + w + '-' + (idx + 1),
          datetime: toKSTDatetime(entry.date, entry.hour),
          classId: classId,
          studentIds: studentIds,
          반명: 반명
        }
      });
    }
  }
}

if (records.length === 0) records.push({ json: { skip: true, message: '생성할 레코드 없음' } });
return records;

const candidates = $('Code - 수업일정 계산').all();
const httpResponse = $input.first().json;
const existingItems = httpResponse.results || [];
const now = new Date();
const targetYear = now.getMonth() === 11 ? now.getFullYear() + 1 : now.getFullYear();
const targetMonth = now.getMonth() === 11 ? 1 : now.getMonth() + 2;
const monthStart = new Date(targetYear, targetMonth - 1, 1).getTime();
const monthEnd = new Date(targetYear, targetMonth, 1).getTime();
const existingSet = new Set();
const classLastKajeong = {};
for (const item of existingItems) {
  const props = item.properties || {};
  const classId = (props['Class']?.relation || [])[0]?.id || null;
  const dateStr = props['수업일정']?.date?.start || '';
  if (!classId || !dateStr) continue;
  const dateTs = new Date(dateStr).getTime();
  if (dateTs >= monthStart && dateTs < monthEnd) existingSet.add(classId + '__' + dateStr.split('T')[0]);
  const 과정Names = (props['과정']?.multi_select || []).map(s => s.name);
  if (과정Names.length > 0) {
    if (!classLastKajeong[classId] || dateStr > classLastKajeong[classId].date) {
      classLastKajeong[classId] = { date: dateStr, 과정: 과정Names };
    }
  }
}
const results = [];
for (const c of candidates) {
  if (c.json.skip) continue;
  const dateOnly = (c.json.datetime || '').split('T')[0];
  const key = c.json.classId + '__' + dateOnly;
  if (!existingSet.has(key)) {
    const lastKajeong = classLastKajeong[c.json.classId];
    results.push({ json: Object.assign({}, c.json, { 과정: lastKajeong ? lastKajeong.과정 : [] }) });
  }
}
if (results.length === 0) results.push({ json: { skip: true, message: '모두 중복 - 생성 없음' } });
return results;

